                   .replace("&mdash;", "—")
                   .replace("&lsquo;", "'")
                   .replace("&rsquo;", "'")
                   .replace("&ldquo;", "\"")
                   .replace("&rdquo;", "\"");
    }

    private String cleanHtml(String text) {
